import{_ as t,o,c as a,ai as r}from"./chunks/framework.DG6aArJf.js";const u=JSON.parse('{"title":"Why DOM Helpers?","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/learning-philosophy.md","filePath":"getting-started/learning-philosophy.md"}'),s={name:"getting-started/learning-philosophy.md"};function n(i,e,l,h,d,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<p><a href="https://github.com/sponsors/giovanni1707" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-%F0%9F%92%96-pink" alt="Sponsor"></a><a href="https://paypal.me/GiovanniSylvain" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/Sponsor-PayPal-blue?logo=paypal" alt="Sponsor"></a></p><h1 id="why-dom-helpers" tabindex="-1">Why DOM Helpers? <a class="header-anchor" href="#why-dom-helpers" aria-label="Permalink to “Why DOM Helpers?”">​</a></h1><h2 id="the-honest-answer" tabindex="-1">The honest answer <a class="header-anchor" href="#the-honest-answer" aria-label="Permalink to “The honest answer”">​</a></h2><p>Plain JavaScript works. The browser gives you <code>document.getElementById</code>, <code>addEventListener</code>, <code>classList</code>, <code>style</code>, <code>localStorage</code> — stable, well-documented, universally supported. For a small project, that&#39;s all you need.</p><p>The friction starts when things grow.</p><p>Functions get longer. The same <code>document.getElementById</code> call appears five times for the same element. State lives in variables scattered across files. When a button should be disabled, you find every place that touches it and update them all manually. When a form submits, a single handler mixes DOM reads, validation logic, API calls, and error display.</p><p>This is not a JavaScript problem. It&#39;s a structure problem. DOM Helpers is the structure.</p><hr><h2 id="what-dom-helpers-is-not" tabindex="-1">What DOM Helpers is not <a class="header-anchor" href="#what-dom-helpers-is-not" aria-label="Permalink to “What DOM Helpers is not”">​</a></h2><p>Before explaining what it is, it helps to be clear about what it isn&#39;t.</p><p><strong>It is not a framework.</strong> It does not control how your application is structured. It does not have opinions about components, lifecycle hooks, or templates. It does not own your render cycle.</p><p><strong>It is not a compiler target.</strong> There is no JSX, no special syntax, no build step required. You write JavaScript. The browser runs JavaScript.</p><p><strong>It is not a virtual DOM.</strong> Updates go directly to the real DOM — immediately, predictably, and visibly in DevTools.</p><p><strong>It is not a replacement for the platform.</strong> <code>querySelector</code>, <code>addEventListener</code>, <code>fetch</code>, <code>localStorage</code> — these still exist and still work. DOM Helpers adds structure around them, not a wall between you and them.</p><hr><h2 id="what-dom-helpers-is" tabindex="-1">What DOM Helpers is <a class="header-anchor" href="#what-dom-helpers-is" aria-label="Permalink to “What DOM Helpers is”">​</a></h2><p>DOM Helpers is a collection of ten modules that each solve one specific category of DOM work:</p><ul><li><strong>Finding elements</strong> — once, with automatic caching</li><li><strong>Updating elements</strong> — with a single consistent syntax for any property</li><li><strong>Working with groups</strong> — helpers for collections, not just individual elements</li><li><strong>Reactive state</strong> — objects that automatically propagate changes</li><li><strong>State-driven rendering</strong> — map state values to DOM configurations declaratively</li><li><strong>Browser storage</strong> — persistence without serialization boilerplate</li><li><strong>Form handling</strong> — read, validate, and submit without manual wiring</li><li><strong>Animations</strong> — awaitable, composable, directly on elements</li><li><strong>Async utilities</strong> — debounce, throttle, fetch with timeout and retry</li><li><strong>Client-side routing</strong> — a full SPA router with guards and transitions</li></ul><p>Each module has a clear, limited purpose. Each can be used independently. Together, they give you the structure that plain JavaScript leaves you to build yourself — every time, from scratch, differently.</p><hr><h2 id="the-learning-philosophy" tabindex="-1">The learning philosophy <a class="header-anchor" href="#the-learning-philosophy" aria-label="Permalink to “The learning philosophy”">​</a></h2><p>DOM Helpers was built with a specific belief: <strong>you should understand what your code is doing.</strong></p><p>Most frontend frameworks solve the readability problem by raising the abstraction level until you no longer see the DOM at all. You write components, the framework decides when and how to render them. This works — but it comes with a cost. When something goes wrong, you debug the framework. When the framework changes, your knowledge partially expires.</p><p>DOM Helpers stays close to the platform. When you use <code>.update()</code>, you are setting properties on a real DOM element. When you use <code>Reactive.state()</code>, you are creating a proxy that tracks property access. When you use <code>Conditions.whenState()</code>, you are declaring what DOM configurations map to what values — and the library applies them by calling the same DOM APIs you already know.</p><p>Nothing is hidden. You can read the source. You can understand the mechanism. You can reason about what the browser is doing because you are still working with the browser.</p><p>This matters for learning. If you understand what DOM Helpers is doing under the hood, you understand the DOM. That knowledge transfers to any project, any library, any framework. The goal is not to make DOM work disappear — it&#39;s to make it manageable while keeping it visible.</p><hr><h2 id="the-comparison-point" tabindex="-1">The comparison point <a class="header-anchor" href="#the-comparison-point" aria-label="Permalink to “The comparison point”">​</a></h2><p>Not React. Not Vue. Not Svelte.</p><p>Those frameworks solve a different problem: large teams, complex UIs, component reuse across projects, design systems. They are excellent at what they do.</p><p>DOM Helpers is for when you do not need a framework. When you want to write JavaScript directly. When you want to add interactivity to an existing page without replacing it. When you want to understand how reactivity works before you trust a compiler to implement it for you. When you want to ship something without a build step.</p><p>The comparison point is <strong>plain JavaScript</strong> — what you&#39;d write without any library. DOM Helpers makes that plain JavaScript cleaner, more consistent, and easier to scale.</p><hr><h2 id="why-not-just-use-jquery" tabindex="-1">Why not just use jQuery? <a class="header-anchor" href="#why-not-just-use-jquery" aria-label="Permalink to “Why not just use jQuery?”">​</a></h2><p>jQuery solved the wrong problem. Its main contribution was cross-browser normalization — something the platform itself solved years ago. <code>$(&#39;.class&#39;)</code> is not meaningfully different from <code>document.querySelectorAll(&#39;.class&#39;)</code> today.</p><p>jQuery does not have a reactive state system. It does not have structured form handling. It does not have a routing solution. It does not help you manage what happens when data changes and the DOM needs to reflect that change.</p><p>DOM Helpers is not a selector convenience. It is a complete system for building interactive DOM-driven applications — in plain JavaScript, without a framework.</p><hr><h2 id="where-to-go-from-here" tabindex="-1">Where to go from here <a class="header-anchor" href="#where-to-go-from-here" aria-label="Permalink to “Where to go from here”">​</a></h2><p>If this resonates, start here:</p><ul><li><strong><a href="./01_what-is-dom-helpers-core.html">What Is DOM Helpers Core</a></strong> — a detailed introduction to the library and its design</li><li><strong><a href="./02_why-dom-helpers-exists.html">Why DOM Helpers Exists</a></strong> — eight concrete problems, shown side-by-side with plain JavaScript</li><li><strong><a href="./03_architecture-overview.html">Architecture Overview</a></strong> — how the ten modules divide responsibility</li><li><strong><a href="./installation.html">Installation</a></strong> — get it running in under two minutes</li></ul>',41)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
